3216 /// corresponding to dead blocks with UndefVal.
3217 void GVNPass::addDeadBlock(BasicBlock *BB) {
3218   SmallVector<BasicBlock *, 4> NewDead;
3219   SmallSetVector<BasicBlock *, 4> DF;
3220 
3221   NewDead.push_back(BB);
3222   while (!NewDead.empty()) {
3223     BasicBlock *D = NewDead.pop_back_val();
3224     if (DeadBlocks.count(D))
3225       continue;
3226 
3227     // All blocks dominated by D are dead.
3228     SmallVector<BasicBlock *, 8> Dom;
3229     DT->getDescendants(D, Dom);
3230     DeadBlocks.insert_range(Dom);
3231 
3232     // Figure out the dominance-frontier(D).
3233     for (BasicBlock *B : Dom) {
3234       for (BasicBlock *S : successors(B)) {
3235         if (DeadBlocks.count(S))
3236           continue;
3237 
3238         bool AllPredDead = true;
3239         for (BasicBlock *P : predecessors(S))
3240           if (!DeadBlocks.count(P)) {
3241             AllPredDead = false;
3242             break;
3243           }
3244 
3245         if (!AllPredDead) {
3246           // S could be proved dead later on. That is why we don't update phi
3247           // operands at this moment.
3248           DF.insert(S);
3249         } else {
3250           // While S is not dominated by D, it is dead by now. This could take
3251           // place if S already have a dead predecessor before D is declared
3252           // dead.
3253           NewDead.push_back(S);
3254         }
3255       }
3256     }
3257   }
3258 
3259   // For the dead blocks' live successors, update their phi nodes by replacing
3260   // the operands corresponding to dead blocks with UndefVal.
3261   for (BasicBlock *B : DF) {
3262     if (DeadBlocks.count(B))
3263       continue;
3264 
3265     // First, split the critical edges. This might also create additional blocks
3266     // to preserve LoopSimplify form and adjust edges accordingly.
3267     SmallVector<BasicBlock *, 4> Preds(predecessors(B));
3268     for (BasicBlock *P : Preds) {
3269       if (!DeadBlocks.count(P))
3270         continue;
3271 
3272       if (is_contained(successors(P), B) &&
3273           isCriticalEdge(P->getTerminator(), B)) {
3274         if (BasicBlock *S = splitCriticalEdges(P, B))
3275           DeadBlocks.insert(P = S);
3276       }
3277     }
3278 
