3292 // If the given branch is recognized as a foldable branch (i.e. conditional
3293 // branch with constant condition), it will perform following analyses and
3294 // transformation.
3295 //  1) If the dead out-coming edge is a critical-edge, split it. Let
3296 //     R be the target of the dead out-coming edge.
3297 //  1) Identify the set of dead blocks implied by the branch's dead outcoming
3298 //     edge. The result of this step will be {X| X is dominated by R}
3299 //  2) Identify those blocks which haves at least one dead predecessor. The
3300 //     result of this step will be dominance-frontier(R).
3301 //  3) Update the PHIs in DF(R) by replacing the operands corresponding to
3302 //     dead blocks with "UndefVal" in an hope these PHIs will optimized away.
3303 //
3304 // Return true iff *NEW* dead code are found.
3305 bool GVNPass::processFoldableCondBr(BranchInst *BI) {
3306   if (!BI || BI->isUnconditional())
3307     return false;
3308 
3309   // If a branch has two identical successors, we cannot declare either dead.
3310   if (BI->getSuccessor(0) == BI->getSuccessor(1))
3311     return false;
3312 
3313   ConstantInt *Cond = dyn_cast<ConstantInt>(BI->getCondition());
3314   if (!Cond)
3315     return false;
3316 
3317   BasicBlock *DeadRoot =
3318       Cond->getZExtValue() ? BI->getSuccessor(1) : BI->getSuccessor(0);
3319   if (DeadBlocks.count(DeadRoot))
3320     return false;
3321 
3322   if (!DeadRoot->getSinglePredecessor())
3323     DeadRoot = splitCriticalEdges(BI->getParent(), DeadRoot);
3324 
3325   addDeadBlock(DeadRoot);
3326   return true;
3327 }
