3000     assert(BlockRPONumber.count(P) && BlockRPONumber.count(CurrentBlock) &&
3001            "Invalid BlockRPONumber map.");
3002     if (BlockRPONumber[P] >= BlockRPONumber[CurrentBlock]) {
3003       NumWithout = 2;
3004       break;
3005     }
3006 
3007     uint32_t TValNo = VN.phiTranslate(P, CurrentBlock, ValNo, *this);
3008     Value *PredV = findLeader(P, TValNo);
3009     if (!PredV) {
3010       PredMap.push_back(std::make_pair(static_cast<Value *>(nullptr), P));
3011       PREPred = P;
3012       ++NumWithout;
3013     } else if (PredV == CurInst) {
3014       // CurInst dominates this predecessor.
3015       NumWithout = 2;
3016       break;
3017     } else {
3018       PredMap.push_back(std::make_pair(PredV, P));
3019       ++NumWith;
3020     }
3021   }
3022 
3023   // Don't do PRE when it might increase code size, i.e. when
3024   // we would need to insert instructions in more than one pred.
3025   if (NumWithout > 1 || NumWith == 0)
3026     return false;
3027 
3028   // We may have a case where all predecessors have the instruction,
3029   // and we just need to insert a phi node. Otherwise, perform
3030   // insertion.
3031   Instruction *PREInstr = nullptr;
3032 
3033   if (NumWithout != 0) {
3034     if (!isSafeToSpeculativelyExecute(CurInst)) {
3035       // It is only valid to insert a new instruction if the current instruction
3036       // is always executed. An instruction with implicit control flow could
3037       // prevent us from doing it. If we cannot speculate the execution, then
3038       // PRE should be prohibited.
3039       if (ICF->isDominatedByICFIFromSameBlock(CurInst))
3040         return false;
3041     }
3042 
3043     // Don't do PRE across indirect branch.
3044     if (isa<IndirectBrInst>(PREPred->getTerminator()))
3045       return false;
3046 
3047     // We can't do PRE safely on a critical edge, so instead we schedule
3048     // the edge to be split and perform the PRE the next time we iterate
3049     // on the function.
3050     unsigned SuccNum = GetSuccessorNumber(PREPred, CurrentBlock);
3051     if (isCriticalEdge(PREPred->getTerminator(), SuccNum)) {
3052       ToSplit.push_back(std::make_pair(PREPred->getTerminator(), SuccNum));
3053       return false;
3054     }
3055     // We need to insert somewhere, so let's give it a shot.
3056     PREInstr = CurInst->clone();
3057     if (!performScalarPREInsertion(PREInstr, PREPred, CurrentBlock, ValNo)) {
3058       // If we failed insertion, make sure we remove the instruction.
3059 #ifndef NDEBUG
3060       verifyRemoved(PREInstr);
3061 #endif
3062       PREInstr->deleteValue();
3063       return false;
3064     }
3065   }
3066 
3067   // Either we should have filled in the PRE instruction, or we should
3068   // not have needed insertions.
3069   assert(PREInstr != nullptr || NumWithout == 0);
3070 
3071   ++NumGVNPRE;
3072 
3073   // Create a PHI to make the value available in this block.
3074   PHINode *Phi = PHINode::Create(CurInst->getType(), PredMap.size(),
3075                                  CurInst->getName() + ".pre-phi");
3076   Phi->insertBefore(CurrentBlock->begin());
3077   for (auto &[V, BB] : PredMap) {
3078     if (V) {
3079       // If we use an existing value in this phi, we have to patch the original
3080       // value because the phi will be used to replace a later value.
3081       patchReplacementInstruction(CurInst, V);
3082       Phi->addIncoming(V, BB);
3083     } else
3084       Phi->addIncoming(PREInstr, PREPred);
3085   }
3086 
3087   VN.add(Phi, ValNo);
3088   // After creating a new PHI for ValNo, the phi translate result for ValNo will
3089   // be changed, so erase the related stale entries in phi translate cache.
3090   VN.eraseTranslateCacheEntry(ValNo, *CurrentBlock);
3091   LeaderTable.insert(ValNo, Phi, CurrentBlock);
3092   Phi->setDebugLoc(CurInst->getDebugLoc());
3093   CurInst->replaceAllUsesWith(Phi);
3094   if (MD && Phi->getType()->isPtrOrPtrVectorTy())
3095     MD->invalidateCachedPointerInfo(Phi);
3096   LeaderTable.erase(ValNo, CurInst, CurrentBlock);
3097 
3098   LLVM_DEBUG(dbgs() << "GVN PRE removed: " << *CurInst << '\n');
3099   removeInstruction(CurInst);
3100 
3101   return true;
3102 }
