3104 /// Perform a purely local form of PRE that looks for diamond
3105 /// control flow patterns and attempts to perform simple PRE at the join point.
3106 bool GVNPass::performPRE(Function &F) {
3107   bool Changed = false;
3108   for (BasicBlock *CurrentBlock : depth_first(&F.getEntryBlock())) {
3109     // Nothing to PRE in the entry block.
3110     if (CurrentBlock == &F.getEntryBlock())
3111       continue;
3112 
3113     // Don't perform PRE on an EH pad.
3114     if (CurrentBlock->isEHPad())
3115       continue;
3116 
3117     for (BasicBlock::iterator BI = CurrentBlock->begin(),
3118                               BE = CurrentBlock->end();
3119          BI != BE;) {
3120       Instruction *CurInst = &*BI++;
3121       Changed |= performScalarPRE(CurInst);
3122     }
3123   }
3124 
3125   if (splitCriticalEdges())
3126     Changed = true;
3127 
3128   return Changed;
3129 }
