3133 BasicBlock *GVNPass::splitCriticalEdges(BasicBlock *Pred, BasicBlock *Succ) {
3134   // GVN does not require loop-simplify, do not try to preserve it if it is not
3135   // possible.
3136   BasicBlock *BB = SplitCriticalEdge(
3137       Pred, Succ,
3138       CriticalEdgeSplittingOptions(DT, LI, MSSAU).unsetPreserveLoopSimplify());
3139   if (BB) {
3140     if (MD)
3141       MD->invalidateCachedPredecessors();
3142     InvalidBlockRPONumbers = true;
3143   }
3144   return BB;
