3147 /// Split critical edges found during the previous
3148 /// iteration that may enable further optimization.
3149 bool GVNPass::splitCriticalEdges() {
3150   if (ToSplit.empty())
3151     return false;
3152 
3153   bool Changed = false;
3154   do {
3155     std::pair<Instruction *, unsigned> Edge = ToSplit.pop_back_val();
3156     Changed |= SplitCriticalEdge(Edge.first, Edge.second,
3157                                  CriticalEdgeSplittingOptions(DT, LI, MSSAU)) !=
3158                nullptr;
3159   } while (!ToSplit.empty());
3160   if (Changed) {
3161     if (MD)
3162       MD->invalidateCachedPredecessors();
3163     InvalidBlockRPONumbers = true;
3164   }
3165   return Changed;
3166 }
